import { signal, computed, effect } from '@angular/core';

const count = signal(0);
const doubled = computed(() => count() * 2);

effect(() => console.log(`count=${count()} doubled=${doubled()}`));

count.set(1);
count.update(c => c + 1); // doubled auto-updates to 4

export class Timer implements OnInit, OnDestroy {
  private id!: any;
  ngOnInit(): void {
    this.id = setInterval(() => console.log('tick'), 1000);
  }
  ngOnDestroy(): void {
    clearInterval(this.id);
  }
}

@Directive({ selector: '[appHighlight]', standalone: true })
export class HighlightDirective {
  constructor(private el: ElementRef) {}
  @HostListener('mouseenter') onEnter() {
    this.el.nativeElement.style.background = 'yellow';
  }
}
// Usage: <p appHighlight>Hover me</p>

@Pipe({ name: 'filter', pure: false, standalone: true })
export class FilterPipe implements PipeTransform {
  transform(items: string[], term: string): string[] {
    return items.filter(i => i.includes(term));
  }
}

